        adaptor.read(&sensor_id, 1);
        hexi::endian::little_to_native_inplace(sensor_id);

        // Read temperatures count and resize vector
        uint32_t temp_count;
        adaptor.read(&temp_count, 1);
        hexi::endian::little_to_native_inplace(temp_count);
        temperatures.resize(temp_count);

        for (auto& temp : temperatures) {
            adaptor.read(&temp, 1);
            hexi::endian::little_to_native_inplace(temp);
        }

        adaptor.read(&pressure, 1);
        hexi::endian::little_to_native_inplace(pressure);
    }
