struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert to little-endian before writing
        adaptor.write(hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(sensor_id));

        for (const auto& temp : temperatures) {
            adaptor.write(hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp));
        }

        adaptor.write(hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure));
    }

    void serialise(auto& adaptor) {
        // Deserialization: read then convert from little-endian to native
        adaptor.read(&sensor_id, 1);
        hexi::endian::little_to_native_inplace(sensor_id);

        // Read temperatures count and resize vector
        uint32_t temp_count;
        adaptor.read(&temp_count, 1);
        hexi::endian::little_to_native_inplace(temp_count);
        temperatures.resize(temp_count);

        for (auto& temp : temperatures) {
            adaptor.read(&temp, 1);
            hexi::endian::little_to_native_inplace(temp);
        }

        adaptor.read(&pressure, 1);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);

    // Serialize the entire structure
    adaptor.serialise(data);

    return buffer;
}

